from flask import Flask, request, jsonify
from prometheus_client import Counter, Histogram, generate_latest, CONTENT_TYPE_LATEST
import time

app = Flask(__name__)

REQUEST_COUNT = Counter('api_requests_total', 'Total API Requests',
                        ['method', 'endpoint', 'user_id', 'api_key'])
REQUEST_LATENCY = Histogram('api_request_latency_seconds', 'Request latency',
                            ['method', 'endpoint', 'user_id', 'api_key'])

@app.before_request
def start_timer():
    request.start_time = time.time()

@app.after_request
def record_request_data(response):
    request_latency = time.time() - request.start_time
    user_id = request.headers.get('User-ID', 'unknown')
    api_key = request.headers.get('API-Key', 'unknown')
    REQUEST_COUNT.labels(request.method, request.path, user_id, api_key).inc()
    REQUEST_LATENCY.labels(request.method, request.path, user_id, api_key).observe(request_latency)
    return response

@app.route('/metrics')
def metrics():
    return generate_latest(), 200, {'Content-Type': CONTENT_TYPE_LATEST}

@app.route('/api', methods=['GET', 'POST'])
def api():
    user_id = request.headers.get('User-ID', 'unknown')
    api_key = request.headers.get('API-Key', 'unknown')
    request_body = request.json if request.is_json else {}
    return jsonify({'message': 'API response', 'user_id': user_id, 'api_key': api_key, 'request_body': request_body})

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)